// ▶ 기타 내용
//     부모 화면 수입일반 오더(C2)
//     (tn_201_02_03b.jsp) 에서 [컨테이너정보] 버튼 클릭 시 오픈 (조회조건 - 오더번호 : DC20604240061)

scwin.saveYn = "N"; //팝업으로 띄워졌을때 parent에 보내는 값
scwin.retrieveYn = "N"; //조회여부

scwin.onpageload = function () {
  scwin.f_FieldClear();
  const arg = $p.getAllParameter();
  const arg2 = arg.paramData.data;

  //이 화면이 팝업인 경우 파라미터 받기 
  if (arg2[0] != null || arg2[0] != "" || arg2[0] != "undefined") {
    // let args = window.dialogArguments;
    // this.ed_cnd_odrNo.Text = args[0].trim();

    ds_cndInfo.set("odrNo", arg2[0]); // 오더번호 데이터맵에 세팅
    let paramInit = ds_cndInfo.get("odrNo"); // 세팅한 오더번호 파라미터 get
    ed_cnd_odrNo.setValue(paramInit);

    //사이즈 조정
    // gr_cntrInfo.style.height = "180";

    if (ed_cnd_odrNo.getValue() != "") {
      // lay_space.style.display = "inline";
      // btn_close.style.display = "inline";
      lay_space.show();
      btn_close.show();
      $c.gus.cfDisableObjects($p, [ed_cnd_odrNo]);
      scwin.f_Retrieve();
    }
  } else {
    //그리드 세팅
    let rowPos = ds_cntrInfo.getRowPosition();
    let rowVal = ds_cntrInfo.getCellData(rowPos, "impExpDomesticClsCd");
    scwin.f_SetGridHeader(ds_cndInfo.get("odrNo"), rowVal);
  }
};

