//조회 조건 초기화
scwin.f_FieldClear = function (e) {
  ed_cnd_odrNo.setValue("");
  ed_cnd_cntrNo.setValue("");
};

//조회
scwin.f_Retrieve = async function () {
  if (ed_cnd_odrNo.getValue().trim() == "") {
    $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["오더번호"]); //@은(는) 필수 입력 항목입니다.
    return;
  }
  let validataVal = await $c.gus.cfValidate($p, [tbl_cndArea]);
  if (validataVal) {
    ds_cndInfo.setEmptyValue();
    ds_cndInfo.set("odrNo", ed_cnd_odrNo.getValue().trim());
    ds_cndInfo.set("cntrNo", ed_cnd_cntrNo.getValue().trim());
    scwin.retrieveYn = "Y";
    $c.sbm.execute($p, sbm_retrieve); // tr_retrieve.Post();
  }
};

//저장하기전에 값 세팅
//부두간 TS인 경우 : 수입온도를 수출온도에도 세팅해야함
//수입,수출온도구분(sd404)을 온도구분(sd403)으로 세팅
scwin.f_setValueBeforeSave = async function () {
  let odrKndCd = "";
  let cntrInfoRows = ds_cntrInfo.getTotalRow();
  for (let i = 0; i < cntrInfoRows; i++) {
    // 수출신고번호 컬럼명 혼용 보정
    ds_cntrInfo.setCellData(i, "expClarNo", ds_cntrInfo.getCellData(i, "expDeclarNo"));
  }
  if (cntrInfoRows > 0) {
    let rowVal = ds_cntrInfo.getRowPosition();
    odrKndCd = ds_cntrInfo.getCellData(rowVal, "odrKndCd"); //오더종류
    //부두간 TS
    if (odrKndCd == "CT") {
      for (i = 0; i < cntrInfoRows; i++) {
        let impTempVal = ds_cntrInfo.getCellData(i, "impTemper");
        let tempClsVal = ds_cntrInfo.getCellData(i, "impTemperCls");
        ds_cntrInfo.setCellData(i, "expTemper", impTempVal);
        ds_cntrInfo.setCellData(i, "expTemperCls", tempClsVal);
      }
    }

    //수입,수출온도구분(sd404) -> 온도구분(sd403)
    let tempVal;
    for (i = 0; i < cntrInfoRows; i++) {
      let clsCdVal = ds_cntrInfo.getCellData(i, "impExpDomesticClsCd");
      if (clsCdVal == "I" && !$c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "impTemper")) && !$c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "impTemperCls")) && ds_cntrInfo.getRowStatusValue(i) == 3 && ds_cntrInfo.getModifiedIndex().length) {
        tempVal = ds_cntrInfo.getCellData(i, "impTemperCls");
      } else if (clsCdVal == "O" && !$c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "expTemper")) && !$c.gus.cfIsNull($p, ds_cntrInfo.getCellData(i, "expTemperCls")) && ds_cntrInfo.getModifiedIndex().length) {
        tempVal = ds_cntrInfo.getCellData(i, "expTemperCls");
      }
      ds_cntrInfo.setCellData(i, "temperCls", tempVal);
    }
  }
};

//저장
scwin.f_Save = async function () {
  let confirmVal = await $c.win.confirm($p, MSG_CM_CRM_001);
  if (confirmVal) {
    //저장하시겠습니까?
    if (ds_cntrInfo.getModifiedIndex().length) {
      let validataVal = await $c.gus.cfValidate($p, [gr_cntrInfo]);
      if (validataVal) {
        await scwin.f_setValueBeforeSave(); //저장하기전에 값세팅
        // $c.sbm.execute(sbm_save); // tr_save.Post();
        await scwin.submitExcute(sbm_save);
      }
    } else {
      $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["컨테이너오더"]); //@은(는) 변경된 사항이 없습니다.
    }
  }
};

/**
 * @method 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {
  let submitObj = $p.getComponentById(e.id);
  switch (submitObj) {
    case sbm_save:
      await scwin.sbm_save_submitdone(e);
      break;
    default:
      break;
  }
};

/**
 * @method 
 * @name submitExcute 
 * @description submit 처리
 */
scwin.submitExcute = async function (sbmObj) {
  const e = await $c.sbm.execute($p, sbmObj);
  if (e.responseJSON.resultDataSet[0].Msg == 'SUCC') {
    if (e.responseJSON.resultDataSet[0].Code == -1) return;
    await scwin.submitdone(e);
  }
  ;
};

