//컨테이너 type이 'RF'인 경우, 온도와 dry여부 둘 중에 하나만 입력해야 함
scwin.f_SetTemperDryByRFCntr = function (ds, gr, row) {
  let type = ds.getCellData(row, "cntrTypCd"); //컨테이너type
  let impTemper = ds.getCellData(row, "impTemper"); //수입온도
  let impDryYn = ds.getCellData(row, "impDryYn"); //수입dry여부
  let expTemper = ds.getCellData(row, "expTemper"); //수출온도
  let expDryYn = ds.getCellData(row, "dryYn"); //수출dry여부

  if (["RF", "RH"].includes(type)) {
    //수입
    if (!$c.gus.cfIsNull($p, impTemper) && impDryYn == 0) {
      gr_cntrInfo.setCellReadOnly(row, "impTemper", false);
      gr_cntrInfo.setCellReadOnly(row, "impTemperCls", false);
      gr_cntrInfo.setCellReadOnly(row, "impDryYn", true);
    } else if ($c.gus.cfIsNull($p, impTemper) && impDryYn == 1) {
      gr_cntrInfo.setCellReadOnly(row, "impTemper", true);
      gr_cntrInfo.setCellReadOnly(row, "impTemperCls", true);
      gr_cntrInfo.setCellReadOnly(row, "impDryYn", false);
    } else {
      gr_cntrInfo.setCellReadOnly(row, "impTemper", false);
      gr_cntrInfo.setCellReadOnly(row, "impDryYn", false);
    }

    //수출
    let expTemperBool, expTemperClsBool, dryYnBool;
    if (!$c.gus.cfIsNull($p, expTemper) && expDryYn == 0) {
      expTemperBool = false;
      expTemperClsBool = false;
      dryYnBool = true;
    } else if ($c.gus.cfIsNull($p, expTemper) && expDryYn == 1) {
      expTemperBool = true;
      expTemperClsBool = true;
      dryYnBool = false;
    } else {
      expTemperBool = false;
      expTemperClsBool = false;
      dryYnBool = false;
    }
    gr_cntrInfo.setCellReadOnly(row, "expTemper", expTemperBool);
    gr_cntrInfo.setCellReadOnly(row, "expTemperCls", expTemperClsBool);
    gr_cntrInfo.setCellReadOnly(row, "dryYn", dryYnBool);
  } else {
    ds.setCellData(row, "impTemper", "");
    ds.setCellData(row, "impDryYn", 0);
    ds.setCellData(row, "expTemper", "");
    ds.setCellData(row, "dryYn", 0);
    gr_cntrInfo.setCellReadOnly(row, "impTemper", true);
    gr_cntrInfo.setCellReadOnly(row, "impDryYn", true);
    gr_cntrInfo.setCellReadOnly(row, "impTemperCls", true);
    gr_cntrInfo.setCellReadOnly(row, "expTemper", true);
    gr_cntrInfo.setCellReadOnly(row, "dryYn", true);
    gr_cntrInfo.setCellReadOnly(row, "expTemperCls", true);
  }
};
