scwin.ed_cnd_odrNo_onkeyup = function (e) {
  let value = ed_cnd_odrNo.getValue();
  value = value.toUpperCase(); // 소문자 -> 대문자
  value = value.replace(/[^A-Z0-9]/g, ""); // 영문 대문자, 숫자만 허용
  ed_cnd_odrNo.setValue(value);
  if (e.keyCode == 13) scwin.f_Retrieve();
};

